import { BrowserRouter, Routes, Route, Link } from "react-router-dom";
import { AuthProvider, useAuth } from "./AuthContext";
import { PrivateRoute, RoleGuard } from "./routeGuards";
import Login from "./components/Login";

function Home() {
    const { user, logout } = useAuth();
    return (
        <div style={{ padding: 16 }}>
            <h2>Home</h2>
            {user ? <>
                <p>Hello, {user.username}</p>
                <p>Roles: {user.roles?.join(", ")}</p>
                <button onClick={logout}>Logout</button>
            </> : <p>Chưa đăng nhập</p>}
            <nav style={{ marginTop: 12 }}>
                <Link to="/">Home</Link> | <Link to="/customers">Customers</Link> | <Link to="/payments">Payments</Link>
            </nav>
        </div>
    );
}
function Customers(){ return <div style={{padding:16}}>Customers (SALES, ADMIN)</div>; }
function Payments(){ return <div style={{padding:16}}>Payments (ACCOUNTANT, ADMIN)</div>; }
function Forbidden(){ return <div style={{padding:16}}><h3>403</h3></div>; }

export default function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <Routes>
                    <Route path="/login" element={<Login/>}/>
                    <Route path="/" element={<PrivateRoute><Home/></PrivateRoute>} />
                    <Route path="/customers" element={
                        <PrivateRoute><RoleGuard roles={["ADMIN","SALES"]}><Customers/></RoleGuard></PrivateRoute>
                    }/>
                    <Route path="/payments" element={
                        <PrivateRoute><RoleGuard roles={["ADMIN","ACCOUNTANT"]}><Payments/></RoleGuard></PrivateRoute>
                    }/>
                    <Route path="/403" element={<Forbidden/>}/>
                </Routes>
            </BrowserRouter>
        </AuthProvider>
    );
}
